") } swiftMsg.append(":77B:DOCUMENTS HELD AT YOUR DISPOSAL PENDING COMPLIANCE OR FURTHER INSTRUCTIONS.
") swiftMsg.append("-}") context.swiftMessageText = swiftMsg.toString()

def fieldMap = [:]
// Simple regex-based parsing for standard tags
def tagRegex = /:([0-9A-Z]{2,3}):([\s\S]*?)(?=\n:[0-9A-Z]{2,3}:|\n-}|$)/
def matcher = (swiftTextCode =~ tagRegex)

while (matcher.find()) {
    def tag = matcher.group(1)
    def value = matcher.group(2).trim()
    fieldMap[tag] = value
}

// Map to logical names for convenience
context.fieldMap = [
    lcNumber: fieldMap['20'],
    formOfCredit: fieldMap['40A'],
    applicableRules: fieldMap['40E'],
    issueDate: fieldMap['31C'],
    expiry: fieldMap['31D'],
    amount: fieldMap['32B'],
    applicant: fieldMap['50'],
    beneficiary: fieldMap['59'],
    descriptionOfGoods: fieldMap['45A'],
    docsRequired: fieldMap['46A'],
    allTags: fieldMap
]

def fieldMap = [:]
def tagRegex = /:([0-9A-Z]{2,3}):([\s\S]*?)(?=\n:[0-9A-Z]{2,3}:|\n-|$)/
def matcher = (swiftTextCode =~ tagRegex)

while (matcher.find()) {
    def tag = matcher.group(1)
    def value = matcher.group(2).trim()
    fieldMap[tag] = value
}

context.fieldMap = [
    lcNumber: fieldMap['20'],
    amendmentNumber: fieldMap['26E'],
    amendmentDetails: fieldMap['79'],
    allTags: fieldMap
]
